const raw = $input.item.json;
const overview = raw.courseOverview || raw;
const seed = Math.floor(Math.random() * 1000000000000);
const imagePrompt = overview.themeImagePrompt || '扁平矢量插画，单线风格，2D扁平设计，无渐变，无阴影，低饱和度的平涂色彩，干净亲和的美学，沉浸式叙事扁平背景，画面无人物无文字，卡通风格的儿童教室场景';

const workflow = {
  "2": {
    "inputs": {
      "unet_name": "qwen_image_fp8_e4m3fn.safetensors",
      "weight_dtype": "fp8_e4m3fn"
    },
    "class_type": "UNETLoader",
    "_meta": { "title": "Load Diffusion Model" }
  },
  "3": {
    "inputs": {
      "clip_name": "qwen_2.5_vl_7b_fp8_scaled.safetensors",
      "type": "qwen_image",
      "device": "default"
    },
    "class_type": "CLIPLoader",
    "_meta": { "title": "Load CLIP" }
  },
  "4": {
    "inputs": {
      "vae_name": "qwen_image_vae.safetensors"
    },
    "class_type": "VAELoader",
    "_meta": { "title": "Load VAE" }
  },
  "6": {
    "inputs": {
      "shift": 3.1000000000000005,
      "model": ["12", 0]
    },
    "class_type": "ModelSamplingAuraFlow",
    "_meta": { "title": "ModelSamplingAuraFlow" }
  },
  "7": {
    "inputs": {
      "text": imagePrompt,
      "clip": ["3", 0]
    },
    "class_type": "CLIPTextEncode",
    "_meta": { "title": "CLIP Text Encode (Prompt)" }
  },
  "8": {
    "inputs": {
      "text": "模糊，低清，畸形，杂乱背景，过多装饰，恐怖，黑暗，血腥，写实照片，油画，过度写实，文字变形，文字模糊，手绘感太重，噪点，复杂纹理，水印，ui界面，多余人物",
      "clip": ["3", 0]
    },
    "class_type": "CLIPTextEncode",
    "_meta": { "title": "CLIP Text Encode (Negative)" }
  },
  "9": {
    "inputs": {
      "width": 1344,
      "height": 768,
      "batch_size": 1
    },
    "class_type": "EmptyLatentImage",
    "_meta": { "title": "Empty Latent Image" }
  },
  "10": {
    "inputs": {
      "seed": seed,
      "steps": 8,
      "cfg": 1,
      "sampler_name": "res_multistep",
      "scheduler": "sgm_uniform",
      "denoise": 1,
      "model": ["6", 0],
      "positive": ["7", 0],
      "negative": ["8", 0],
      "latent_image": ["9", 0]
    },
    "class_type": "KSampler",
    "_meta": { "title": "KSampler" }
  },
  "12": {
    "inputs": {
      "lora_name": "Qwen-Image-Lightning-8steps-V1.0.safetensors",
      "strength_model": 1,
      "model": ["2", 0]
    },
    "class_type": "LoraLoaderModelOnly",
    "_meta": { "title": "LoraLoaderModelOnly" }
  },
  "14": {
    "inputs": {
      "filename_prefix": "course-theme",
      "images": ["15", 0]
    },
    "class_type": "SaveImage",
    "_meta": { "title": "Save Image" }
  },
  "15": {
    "inputs": {
      "samples": ["10", 0],
      "vae": ["4", 0]
    },
    "class_type": "VAEDecode",
    "_meta": { "title": "VAE Decode" }
  }
};

return {
  courseOverview: overview,
  comfyuiPayload: JSON.stringify({ prompt: workflow })
};

const promptId = $input.item.json.prompt_id;
const courseOverview = $('构建图片工作流').first().json.courseOverview;

const maxAttempts = 60;
for (let i = 0; i < maxAttempts; i++) {
  await new Promise(r => setTimeout(r, 3000));

  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://vcbj5meqyp1y7ifw-8188.container.x-gpu.com/history/${promptId}`,
      json: true
    });
    const taskData = Object.values(res)[0];

    if (taskData && taskData.outputs) {
      const images = taskData.outputs['14']?.images || [];
      if (images.length > 0) {
        const img = images[0];
        const imageUrl = `/ai/view?filename=${img.filename}&subfolder=${img.subfolder || ''}&type=${img.type || 'output'}`;
        return {
          courseOverview,
          themeImageUrl: imageUrl
        };
      }
    }

    if (taskData?.status?.status_str === 'error') {
      return {
        courseOverview,
        themeImageUrl: null,
        error: '图片生成失败'
      };
    }
  } catch (e) {
    // 继续重试
  }
}

return {
  courseOverview,
  themeImageUrl: null,
  error: '图片生成超时'
};
